                    beatNode.addElement("Tremolo").innerText = "1/4"
                }
                3.0 -> 
                {
                    beatNode.addElement("Tremolo").innerText = "1/8"
                }
                else -> { }
            }
        }
        if (beat.hasChord)
        {
            beatNode.addElement("Chord").setCData(beat.chordId!!)
        }
        if (beat.crescendo != com.omnifret.gplayer.model.CrescendoType.None)
        {
            beatNode.addElement("Hairpin").innerText = beat.crescendo.toString()
        }
        when (beat.brushType)
        {
            com.omnifret.gplayer.model.BrushType.ArpeggioUp -> 
            {
                beatNode.addElement("Arpeggio").innerText = "Up"
            }
            com.omnifret.gplayer.model.BrushType.ArpeggioDown -> 
            {
                beatNode.addElement("Arpeggio").innerText = "Down"
            }
            else -> { }
        }
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(beat.text)))
        {
            beatNode.addElement("FreeText").setCData(beat.text!!)
        }
        when (beat.graceType)
        {
            com.omnifret.gplayer.model.GraceType.OnBeat, com.omnifret.gplayer.model.GraceType.BeforeBeat -> 
            {
                beatNode.addElement("GraceNotes").innerText = beat.graceType.toString()
            }
            else -> { }
        }
        if (beat.ottava != com.omnifret.gplayer.model.Ottavia.Regular)
        {
            beatNode.addElement("Ottavia").innerText = beat.ottava.toString().substr(1.0)
        }
        if (beat.hasWhammyBar)
        {
            this._writeWhammyNode(beatNode, beat)
        }
        if (beat.isLegatoOrigin || beat.isLegatoDestination)
        {
            var legato: com.omnifret.gplayer.xml.XmlNode = beatNode.addElement("Legato")
            legato.attributes.set("origin", if(beat.isLegatoOrigin)  "true" else "false")
            legato.attributes.set("destination", if(beat.isLegatoDestination)  "true" else "false")
        }
        this._writeRhythm(beatNode, beat, rhythms)
        if (beat.preferredBeamDirection != null)
        {
            when (beat.preferredBeamDirection!!)
            {
                com.omnifret.gplayer.rendering.utils.BeamDirection.Up -> 
                {
                    beatNode.addElement("TransposedPitchStemOrientation").innerText = "Upward"
                    beatNode.addElement("UserTransposedPitchStemOrientation").innerText = "Upward"
                }
                com.omnifret.gplayer.rendering.utils.BeamDirection.Down -> 
                {
                    beatNode.addElement("TransposedPitchStemOrientation").innerText = "Downward"
                    beatNode.addElement("UserTransposedPitchStemOrientation").innerText = "Downward"
                }
                else -> { }
            }
        }
        beatNode.addElement("ConcertPitchStemOrientation").innerText = "Undefined"
        if (beat.slashed)
        {
            beatNode.addElement("Slashed")
        }
        if (beat.deadSlapped)
        {
            beatNode.addElement("DeadSlapped")
        }
        if (beat.notes.length > 0)
        {
            beatNode.addElement("Notes").innerText = beat.notes.map(fun(n: com.omnifret.gplayer.model.Note): Double{
                return n.id
            }
            ).join(" ")
        }
        if (beat.golpe != com.omnifret.gplayer.model.GolpeType.None)
        {
            beatNode.addElement("Golpe").innerText = beat.golpe.toString()
        }
        if (beat.wahPedal != com.omnifret.gplayer.model.WahPedal.None)
        {
            beatNode.addElement("Wah").innerText = beat.wahPedal.toString()
        }
        if (beat.showTimer)
        {
            beatNode.addElement("Timer").innerText = (beat.timer ?: 0.0).toInvariantString()
        }
        this._writeBeatProperties(beatNode, beat)
        this._writeBeatXProperties(beatNode, beat)
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(beat.lyrics)) && beat.lyrics!!.length > 0))
        {
