    /**
     */
    private fun _writeRhythm(parent: com.omnifret.gplayer.xml.XmlNode, beat: com.omnifret.gplayer.model.Beat, rhythms: com.omnifret.gplayer.xml.XmlNode): Unit{
        var rhythmId: String = """${(beat.duration).toTemplate()}_${(beat.dots).toTemplate()}_${(beat.tupletNumerator).toTemplate()}_${(beat.tupletDenominator).toTemplate()}';"""
        var rhythm: String
        if (!this._rhythmIdLookup.has(rhythmId))
        {
            rhythm = this._rhythmIdLookup.size.toInvariantString()
            this._rhythmIdLookup.set(rhythmId, rhythm)
            var rhythmNode: com.omnifret.gplayer.xml.XmlNode = rhythms.addElement("Rhythm")
            rhythmNode.attributes.set("id", rhythm)
            if (beat.hasTuplet)
            {
                var tupletNode: com.omnifret.gplayer.xml.XmlNode = rhythmNode.addElement("PrimaryTuplet")
                tupletNode.attributes.set("num", beat.tupletNumerator.toInvariantString())
                tupletNode.attributes.set("den", beat.tupletDenominator.toInvariantString())
            }
            if (beat.dots > 0)
            {
                rhythmNode.addElement("AugmentationDot").attributes.set("count", beat.dots.toInvariantString())
            }
            var noteValue: String = "Quarter"
            when (beat.duration)
            {
                com.omnifret.gplayer.model.Duration.QuadrupleWhole -> 
                {
                    noteValue = "Long"
                }
                com.omnifret.gplayer.model.Duration.DoubleWhole -> 
                {
                    noteValue = "DoubleWhole"
                }
                com.omnifret.gplayer.model.Duration.Whole -> 
                {
                    noteValue = "Whole"
                }
                com.omnifret.gplayer.model.Duration.Half -> 
                {
                    noteValue = "Half"
                }
                com.omnifret.gplayer.model.Duration.Quarter -> 
                {
                    noteValue = "Quarter"
                }
                com.omnifret.gplayer.model.Duration.Eighth -> 
                {
                    noteValue = "Eighth"
                }
                com.omnifret.gplayer.model.Duration.Sixteenth -> 
                {
                    noteValue = "16th"
                }
                com.omnifret.gplayer.model.Duration.ThirtySecond -> 
                {
                    noteValue = "32nd"
                }
                com.omnifret.gplayer.model.Duration.SixtyFourth -> 
                {
                    noteValue = "64th"
                }
                com.omnifret.gplayer.model.Duration.OneHundredTwentyEighth -> 
                {
                    noteValue = "128th"
                }
                com.omnifret.gplayer.model.Duration.TwoHundredFiftySixth -> 
                {
                    noteValue = "256th"
                }
                else -> { }
            }
            rhythmNode.addElement("NoteValue").innerText = noteValue
        }
        else 
        {
            rhythm = this._rhythmIdLookup.get(rhythmId)!!
        }
        parent.addElement("Rhythm").attributes.set("ref", rhythm)
    }
    
