    /**
     */
    private fun _writeStandardWhammy(parent: com.omnifret.gplayer.xml.XmlNode, whammyBarPoints: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.BendPoint>): Unit{
        var whammyNode: com.omnifret.gplayer.xml.XmlNode = parent.addElement("Whammy")
        var whammyOrigin: com.omnifret.gplayer.model.BendPoint = whammyBarPoints[(0).toInt()]
        var whammyDestination: com.omnifret.gplayer.model.BendPoint = whammyBarPoints[(whammyBarPoints.length - (1.0).toDouble()).toInt()]
        var whammyMiddle1: com.omnifret.gplayer.model.BendPoint
        var whammyMiddle2: com.omnifret.gplayer.model.BendPoint
        when (whammyBarPoints.length)
        {
            4.0 -> 
            {
                whammyMiddle1 = whammyBarPoints[(1).toInt()]
                whammyMiddle2 = whammyBarPoints[(2).toInt()]
            }
            3.0 -> 
            {
                whammyMiddle1 = whammyBarPoints[(1).toInt()]
                whammyMiddle2 = whammyBarPoints[(1).toInt()]
            }
            else -> 
            {
                whammyMiddle1 = com.omnifret.gplayer.model.BendPoint((whammyOrigin.offset + whammyDestination.offset) / (2.0).toDouble(), (whammyOrigin.value + whammyDestination.value) / (2.0).toDouble())
                whammyMiddle2 = whammyMiddle1
            }
        }
        whammyNode.attributes.set("destinationOffset", this._toBendOffset(whammyDestination.offset).toInvariantString())
        whammyNode.attributes.set("destinationValue", this._toBendValue(whammyDestination.value).toInvariantString())
        whammyNode.attributes.set("middleOffset1", this._toBendOffset(whammyMiddle1.offset).toInvariantString())
        whammyNode.attributes.set("middleOffset2", this._toBendOffset(whammyMiddle2.offset).toInvariantString())
        whammyNode.attributes.set("middleValue", this._toBendValue(whammyMiddle1.value).toInvariantString())
        whammyNode.attributes.set("originOffset", this._toBendOffset(whammyOrigin.offset).toInvariantString())
        whammyNode.attributes.set("originValue", this._toBendValue(whammyOrigin.value).toInvariantString())
    }
    
