    /**
     */
    private fun _writeMasterTrackNode(parent: com.omnifret.gplayer.xml.XmlNode, score: com.omnifret.gplayer.model.Score): Unit{
        var masterTrackNode: com.omnifret.gplayer.xml.XmlNode = parent.addElement("MasterTrack")
        masterTrackNode.addElement("Tracks").innerText = score.tracks.map(fun(t: com.omnifret.gplayer.model.Track): Double{
            return t.index
        }
        ).join(" ")
        var automations: com.omnifret.gplayer.xml.XmlNode = masterTrackNode.addElement("Automations")
        if (score.masterBars.length > 0 && score.masterBars[(0).toInt()].isAnacrusis)
        {
            masterTrackNode.addElement("Anacrusis")
        }
        if (score.masterBars[(0).toInt()].tempoAutomations.length == 0.0)
        {
            var initialTempoAutomation: com.omnifret.gplayer.xml.XmlNode = automations.addElement("Automation")
            initialTempoAutomation.addElement("Type").innerText = "Tempo"
            initialTempoAutomation.addElement("Linear").innerText = "false"
            initialTempoAutomation.addElement("Bar").innerText = "0"
            initialTempoAutomation.addElement("Position").innerText = "0"
            initialTempoAutomation.addElement("Visible").innerText = "true"
            initialTempoAutomation.addElement("Value").innerText = """${(score.tempo).toTemplate()} 2"""
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(score.tempoLabel)))
            {
                initialTempoAutomation.addElement("Text").innerText = score.tempoLabel
            }
        }
        var initialSyncPoint: com.omnifret.gplayer.model.Automation? = if(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(score.masterBars[(0).toInt()].syncPoints)))  score.masterBars[(0).toInt()].syncPoints!!.find(fun(p: com.omnifret.gplayer.model.Automation): Boolean{
            return p.ratioPosition == 0.0 && p.syncPointValue!!.barOccurence == 0.0
        }
        ) else null
        var millisecondPadding: Double = if(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(initialSyncPoint)))  initialSyncPoint!!.syncPointValue!!.millisecondOffset else 0.0
        this._backingTrackFramePadding = (((-1.0 * ((millisecondPadding / (1000.0).toDouble()) * com.omnifret.gplayer.exporter.GpifWriter._sampleRate))).toInt() or 0).toDouble()
        var modifiedTempoLookup: com.omnifret.gplayer.util.Lazy<com.omnifret.gplayer.collections.Map<com.omnifret.gplayer.model.Automation, com.omnifret.gplayer.synth.BackingTrackSyncPoint>> = com.omnifret.gplayer.util.Lazy<com.omnifret.gplayer.collections.Map<com.omnifret.gplayer.model.Automation, com.omnifret.gplayer.synth.BackingTrackSyncPoint>>(fun(): com.omnifret.gplayer.collections.Map<com.omnifret.gplayer.model.Automation, com.omnifret.gplayer.synth.BackingTrackSyncPoint>{
            return com.omnifret.gplayer.midi.MidiFileGenerator.buildModifiedTempoLookup(score)
        }
        )
        for (mb in score.masterBars)
        {
            for (automation in mb.tempoAutomations)
            {
                var tempoAutomation: com.omnifret.gplayer.xml.XmlNode = automations.addElement("Automation")
                tempoAutomation.addElement("Type").innerText = "Tempo"
                tempoAutomation.addElement("Linear").innerText = if(automation.isLinear)  "true" else "false"
                tempoAutomation.addElement("Bar").innerText = mb.index.toInvariantString()
                tempoAutomation.addElement("Position").innerText = automation.ratioPosition.toInvariantString()
                tempoAutomation.addElement("Visible").innerText = if(automation.isVisible)  "true" else "false"
                tempoAutomation.addElement("Value").innerText = """${(automation.value).toTemplate()} 2"""
                if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(automation.text)))
                {
                    tempoAutomation.addElement("Text").innerText = automation.text
                }
            }
            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(mb.syncPoints)))
            {
                for (syncPoint in mb.syncPoints!!)
                {
                    var syncPointAutomation: com.omnifret.gplayer.xml.XmlNode = automations.addElement("Automation")
                    syncPointAutomation.addElement("Type").innerText = "SyncPoint"
                    syncPointAutomation.addElement("Linear").innerText = "false"
                    syncPointAutomation.addElement("Bar").innerText = mb.index.toInvariantString()
                    syncPointAutomation.addElement("Position").innerText = syncPoint.ratioPosition.toInvariantString()
                    syncPointAutomation.addElement("Visible").innerText = if(syncPoint.isVisible)  "true" else "false"
                    var value: com.omnifret.gplayer.xml.XmlNode = syncPointAutomation.addElement("Value")
                    value.addElement("BarIndex").innerText = mb.index.toInvariantString()
                    value.addElement("BarOccurrence").innerText = syncPoint.syncPointValue!!.barOccurence.toInvariantString()
                    value.addElement("ModifiedTempo").innerText = modifiedTempoLookup.value.get(syncPoint)!!.syncBpm.toInvariantString()
                    value.addElement("OriginalTempo").innerText = score.tempo.toInvariantString()
                    var frameOffset: Double = ((syncPoint.syncPointValue!!.millisecondOffset - millisecondPadding) / (1000.0).toDouble()) * com.omnifret.gplayer.exporter.GpifWriter._sampleRate
                    frameOffset = com.omnifret.gplayer.core.ecmaScript.Math.floor(frameOffset + 0.5)
                    value.addElement("FrameOffset").innerText = frameOffset.toInvariantString()
                }
            }
        }
    }
    
