    /**
     */
    private fun _writeTrackNode(parent: com.omnifret.gplayer.xml.XmlNode, track: com.omnifret.gplayer.model.Track): Unit{
        var trackNode: com.omnifret.gplayer.xml.XmlNode = parent.addElement("Track")
        trackNode.attributes.set("id", track.index.toInvariantString())
        trackNode.addElement("Name").setCData(track.name)
        trackNode.addElement("ShortName").setCData(track.shortName)
        trackNode.addElement("Color").innerText = """${(track.color.r).toTemplate()} ${(track.color.g).toTemplate()} ${(track.color.b).toTemplate()}"""
        trackNode.addElement("SystemsDefautLayout").innerText = track.defaultSystemsLayout.toInvariantString()
        trackNode.addElement("SystemsLayout").innerText = track.systemsLayout.join(" ")
        trackNode.addElement("AutoBrush")
        trackNode.addElement("PalmMute").innerText = "0"
        trackNode.addElement("PlayingStyle").innerText = if(com.omnifret.gplayer.midi.GeneralMidi.isGuitar(track.playbackInfo.program))  "StringedPick" else "Default"
        trackNode.addElement("UseOneChannelPerString")
        trackNode.addElement("IconId").innerText = com.omnifret.gplayer.exporter.GpifSoundMapper.getIconId(track.playbackInfo).toInvariantString()
        this._writeInstrumentSetNode(trackNode, track)
        this._writeTransposeNode(trackNode, track)
        this._writeRseNode(trackNode, track)
        trackNode.addElement("ForcedSound").innerText = "-1"
        this._writeMidiConnectionNode(trackNode, track)
        if (track.playbackInfo.isSolo)
        {
            trackNode.addElement("PlaybackState").innerText = "Solo"
        }
        else if (track.playbackInfo.isMute)
        {
            trackNode.addElement("PlaybackState").innerText = "Mute"
        }
        else 
        {
            trackNode.addElement("PlaybackState").innerText = "Default"
        }
        trackNode.addElement("AudioEngineState").innerText = "MIDI"
        this._writeLyricsNode(trackNode, track)
        this._writeStavesNode(trackNode, track)
        this._writeSoundsAndAutomations(trackNode, track)
    }
    
    /**
     */
    private fun _writeSoundAndAutomation(soundsNode: com.omnifret.gplayer.xml.XmlNode, 
    automationsNode: com.omnifret.gplayer.xml.XmlNode, 
    name: String, 
    path: String, 
    role: String, 
    barIndex: Double, 
    program: Double, 
    bank: Double, 
    ratioPosition: Double = 0.0): Unit{
        var soundNode: com.omnifret.gplayer.xml.XmlNode = soundsNode.addElement("Sound")
        soundNode.addElement("Name").setCData(name)
        soundNode.addElement("Label").setCData(name)
        soundNode.addElement("Path").setCData(path)
        soundNode.addElement("Role").setCData(role)
        var midi: com.omnifret.gplayer.xml.XmlNode = soundNode.addElement("MIDI")
        var lsbMsb: com.omnifret.gplayer.core.IDoubleDoubleArrayTuple = com.omnifret.gplayer.midi.GeneralMidi.bankToLsbMsb(bank)
        midi.addElement("LSB").innerText = lsbMsb.v0.toInvariantString()
        midi.addElement("MSB").innerText = lsbMsb.v1.toInvariantString()
        midi.addElement("Program").innerText = program.toInvariantString()
        var automationNode: com.omnifret.gplayer.xml.XmlNode = automationsNode.addElement("Automation")
        automationNode.addElement("Type").innerText = "Sound"
        automationNode.addElement("Linear").innerText = "false"
        automationNode.addElement("Bar").innerText = barIndex.toInvariantString()
        automationNode.addElement("Position").innerText = ratioPosition.toInvariantString()
        automationNode.addElement("Visible").innerText = "true"
        automationNode.addElement("Value").setCData("""${(path).toTemplate()};${(name).toTemplate()};${(role).toTemplate()}""")
    }
    
    /**
     */
    private fun _writeSoundsAndAutomations(trackNode: com.omnifret.gplayer.xml.XmlNode, track: com.omnifret.gplayer.model.Track): Unit{
        var soundsNode: com.omnifret.gplayer.xml.XmlNode = trackNode.addElement("Sounds")
        var automationsNode: com.omnifret.gplayer.xml.XmlNode = trackNode.addElement("Automations")
        if (track.staves.length > 0 && track.staves[(0).toInt()].bars.length > 0)
        {
            var trackSoundName: String = """Track_${(track.index).toTemplate()}_Initial"""
            var trackSoundPath: String = """Midi/${(track.playbackInfo.program).toTemplate()}"""
            var trackSoundRole: String = "Factory"
            var trackSoundWritten: Boolean = false
            var bank: Double = track.playbackInfo.bank
            for (staff in track.staves)
            {
                for (bar in staff.bars)
                {
                    for (voice in bar.voices)
                    {
                        for (beat in voice.beats)
                        {
                            var soundAutomation: com.omnifret.gplayer.model.Automation? = beat.getAutomation(com.omnifret.gplayer.model.AutomationType.Instrument)
                            var isTrackSound: Boolean = bar.index == 0.0 && beat.index == 0.0
                            var bankAutomation: com.omnifret.gplayer.model.Automation? = beat.getAutomation(com.omnifret.gplayer.model.AutomationType.Bank)
                            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(bankAutomation)))
                            {
                                bank = bankAutomation!!.value
                            }
                            if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(soundAutomation)))
                            {
                                var name: String = if(isTrackSound)  trackSoundName else """ProgramChange_${(beat.id).toTemplate()}"""
                                var path: String = if(isTrackSound)  trackSoundPath else """Midi/${(soundAutomation!!.value).toTemplate()}"""
                                var role: String = if(isTrackSound)  trackSoundRole else "User"
                                if (!isTrackSound && !trackSoundWritten)
                                {
                                    this._writeSoundAndAutomation(
                                        soundsNode
                                        , 
                                        automationsNode
                                        , 
                                        trackSoundName
                                        , 
                                        trackSoundPath
                                        , 
                                        (trackSoundRole.toString())
                                        , 
                                        track.staves[(0).toInt()].bars[(0).toInt()].index
                                        , 
                                        track.playbackInfo.program
                                        , 
                                        track.playbackInfo.bank
                                    
                                    )
                                    trackSoundWritten = true
                                }
                                this._writeSoundAndAutomation(
                                    soundsNode
                                    , 
                                    automationsNode
                                    , 
                                    name
                                    , 
                                    path
                                    , 
                                    (role.toString())
                                    , 
                                    bar.index
                                    , 
                                    soundAutomation!!.value
                                    , 
                                    bank
                                    , 
                                    soundAutomation!!.ratioPosition
                                
                                )
                                if (isTrackSound)
                                {
                                    trackSoundWritten = true
                                }
                            }
                        }
                    }
                }
            }
        }
        for (s in track.staves)
        {
            for (b in s.bars)
            {
                for (sustainPedal in b.sustainPedals)
                {
                    if (sustainPedal.pedalType != com.omnifret.gplayer.model.SustainPedalMarkerType.Hold)
                    {
                        var automation: com.omnifret.gplayer.xml.XmlNode = automationsNode.addElement("Automation")
                        automation.addElement("Type").innerText = "SustainPedal"
                        automation.addElement("Linear").innerText = "false"
                        automation.addElement("Bar").innerText = b.index.toInvariantString()
                        automation.addElement("Position").innerText = sustainPedal.ratioPosition.toInvariantString()
                        automation.addElement("Visible").innerText = "true"
                        when (sustainPedal.pedalType)
                        {
                            com.omnifret.gplayer.model.SustainPedalMarkerType.Down -> 
                            {
                                automation.addElement("Value").innerText = "0 1"
                            }
                            com.omnifret.gplayer.model.SustainPedalMarkerType.Up -> 
                            {
                                automation.addElement("Value").innerText = "0 3"
                            }
                            else -> { }
                        }
                    }
                }
            }
        }
    }
    
    /**
     */
    private fun _writeMidiConnectionNode(trackNode: com.omnifret.gplayer.xml.XmlNode, track: com.omnifret.gplayer.model.Track): Unit{
        var midiConnection: com.omnifret.gplayer.xml.XmlNode = trackNode.addElement("MidiConnection")
        midiConnection.addElement("Port").innerText = track.playbackInfo.port.toInvariantString()
        midiConnection.addElement("PrimaryChannel").innerText = track.playbackInfo.primaryChannel.toInvariantString()
        midiConnection.addElement("SecondaryChannel").innerText = track.playbackInfo.secondaryChannel.toInvariantString()
        midiConnection.addElement("ForeOneChannelPerString").innerText = "false"
    }
    
    /**
     */
    private fun _writeRseNode(trackNode: com.omnifret.gplayer.xml.XmlNode, track: com.omnifret.gplayer.model.Track): Unit{
        var rse: com.omnifret.gplayer.xml.XmlNode = trackNode.addElement("RSE")
        var channelStrip: com.omnifret.gplayer.xml.XmlNode = rse.addElement("ChannelStrip")
        channelStrip.attributes.set("version", "E56")
        var channelStripParameters: com.omnifret.gplayer.xml.XmlNode = channelStrip.addElement("Parameters")
        channelStripParameters.innerText = """0.5 0.5 0.5 0.5 0.5 0.5 0.5 0.5 0.5 1 0.5 ${(track.playbackInfo.balance / (16.0).toDouble()).toTemplate()} ${(track.playbackInfo.volume / (16.0).toDouble()).toTemplate()} 0.5 0.5 0.5"""
    }
    
    /**
     */
    private fun _writeStavesNode(trackNode: com.omnifret.gplayer.xml.XmlNode, track: com.omnifret.gplayer.model.Track): Unit{
        var staves: com.omnifret.gplayer.xml.XmlNode = trackNode.addElement("Staves")
        for (staff in track.staves)
        {
            this._writeStaffNode(staves, staff)
        }
    }
    
    /**
     */
    private fun _writeStaffNode(parent: com.omnifret.gplayer.xml.XmlNode, staff: com.omnifret.gplayer.model.Staff): Unit{
        var staffNode: com.omnifret.gplayer.xml.XmlNode = parent.addElement("Staff")
        var properties: com.omnifret.gplayer.xml.XmlNode = staffNode.addElement("Properties")
        this._writeSimplePropertyNode(properties, "CapoFret", "Fret", staff.capo.toInvariantString())
        this._writeSimplePropertyNode(properties, "FretCount", "Fret", "24")
        if (staff.tuning.length > 0)
        {
            var tuningProperty: com.omnifret.gplayer.xml.XmlNode = properties.addElement("Property")
            tuningProperty.attributes.set("name", "Tuning")
            tuningProperty.addElement("Pitches").innerText = staff.tuning.slice().reverse().join(" ")
            tuningProperty.addElement("Label").setCData(staff.tuningName)
            tuningProperty.addElement("LabelVisible").innerText = if(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(staff.tuningName)))  "true" else "false"
            tuningProperty.addElement("Flat")
            when (staff.tuning.length)
            {
                3.0 -> 
                {
                    tuningProperty.addElement("Instrument").innerText = "Shamisen"
                }
                4.0 -> 
                {
                    if (staff.track.playbackInfo.program == 105.0)
                    {
                        tuningProperty.addElement("Instrument").innerText = "Banjo"
                    }
                    else if (staff.track.playbackInfo.program == 42.0)
                    {
                        tuningProperty.addElement("Instrument").innerText = "Cello"
                    }
                    else if (staff.track.playbackInfo.program == 43.0)
                    {
                        tuningProperty.addElement("Instrument").innerText = "Contrabass"
                    }
                    else if (staff.track.playbackInfo.program == 40.0)
                    {
                        tuningProperty.addElement("Instrument").innerText = "Violin"
                    }
                    else if (staff.track.playbackInfo.program == 41.0)
                    {
                        tuningProperty.addElement("Instrument").innerText = "Viola"
                    }
                    else 
                    {
                        tuningProperty.addElement("Instrument").innerText = "Bass"
                    }
                }
                5.0 -> 
                {
                    if (staff.track.playbackInfo.program == 105.0)
                    {
                        tuningProperty.addElement("Instrument").innerText = "Banjo"
                    }
                    else 
                    {
                        tuningProperty.addElement("Instrument").innerText = "Bass"
                    }
                }
                6.0 -> 
                {
                    if (staff.track.playbackInfo.program == 105.0)
                    {
                        tuningProperty.addElement("Instrument").innerText = "Banjo"
                    }
                    else if (staff.track.playbackInfo.program <= 39)
                    {
                        tuningProperty.addElement("Instrument").innerText = "Bass"
                    }
                    else 
                    {
                        tuningProperty.addElement("Instrument").innerText = "Guitar"
                    }
                }
                7.0 -> 
                {
                    if (staff.track.playbackInfo.program <= 39)
                    {
                        tuningProperty.addElement("Instrument").innerText = "Bass"
                    }
                    else 
                    {
                        tuningProperty.addElement("Instrument").innerText = "Guitar"
                    }
                }
                else -> 
                {
                    tuningProperty.addElement("Instrument").innerText = "Guitar"
                }
            }
        }
        this._writeSimplePropertyNode(properties, "PartialCapoFret", "Fret", "0")
        this._writeSimplePropertyNode(properties, "PartialCapoStringFlags", "Bitset", staff.tuning.map(fun(_: Double): String{
            return "0"
        }
        ).join(""))
        this._writeSimplePropertyNode(properties, "TuningFlat", "Enable", null)
        this._writeDiagramCollection(properties, staff, "DiagramCollection")
        this._writeDiagramCollection(properties, staff, "DiagramWorkingSet")
    }
    
    /**
     */
    private fun _writeDiagramCollection(properties: com.omnifret.gplayer.xml.XmlNode, staff: com.omnifret.gplayer.model.Staff, name: String): Unit{
        var diagramCollectionProperty: com.omnifret.gplayer.xml.XmlNode = properties.addElement("Property")
        diagramCollectionProperty.attributes.set("name", name)
        var diagramCollectionItems: com.omnifret.gplayer.xml.XmlNode = diagramCollectionProperty.addElement("Items")
        var sc: com.omnifret.gplayer.collections.Map<String, com.omnifret.gplayer.model.Chord>? = staff.chords
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(sc)))
        {
            for ((id, chord) in sc!!)
            {
                var diagramCollectionItem: com.omnifret.gplayer.xml.XmlNode = diagramCollectionItems.addElement("Item")
                diagramCollectionItem.attributes.set("id", id)
                diagramCollectionItem.attributes.set("name", chord.name)
                var diagram: com.omnifret.gplayer.xml.XmlNode = diagramCollectionItem.addElement("Diagram")
                diagram.attributes.set("stringCount", chord.strings.length.toInvariantString())
                diagram.attributes.set("fretCount", "5")
                diagram.attributes.set("baseFret", (chord.firstFret - (1.0).toDouble()).toInvariantString())
                diagram.attributes.set("barStates", chord.strings.map(fun(_: Double): String{
                    return "1"
                }
                ).join(" "))
                var frets: com.omnifret.gplayer.collections.DoubleList = com.omnifret.gplayer.collections.DoubleList(
                )
                
                var fretToStrings: com.omnifret.gplayer.collections.DoubleObjectMap<com.omnifret.gplayer.collections.DoubleList> = com.omnifret.gplayer.collections.DoubleObjectMap<com.omnifret.gplayer.collections.DoubleList>()
                if (true) {
                    var i: Double = 0.0
                    
                    while(i < chord.strings.length){
                        var chordFret: Double = chord.strings[(i).toInt()]
                        if (chordFret != -1.0)
                        {
                            var fretNode: com.omnifret.gplayer.xml.XmlNode = diagram.addElement("Fret")
                            var chordString: Double = chord.strings.length - (1.0).toDouble() - i
                            fretNode.attributes.set("string", chordString.toInvariantString())
                            fretNode.attributes.set("fret", (chordFret - chord.firstFret + 1.0).toInvariantString())
                            if (!fretToStrings.has(chordFret))
                            {
                                fretToStrings.set(chordFret, com.omnifret.gplayer.collections.DoubleList(
                                )
                                )
                                frets.push(chordFret)
                            }
                            fretToStrings.get(chordFret)!!.push(chordString)
                        }
                        i++
                    }
                }
                frets.sort()
                var fingering: com.omnifret.gplayer.xml.XmlNode = diagram.addElement("Fingering")
                if (chord.barreFrets.length > 0)
                {
                    var fingers: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.Fingers> = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.Fingers>(
                        com.omnifret.gplayer.model.Fingers.LittleFinger, com.omnifret.gplayer.model.Fingers.AnnularFinger, com.omnifret.gplayer.model.Fingers.MiddleFinger, com.omnifret.gplayer.model.Fingers.IndexFinger)
                    
                    for (fret in frets)
                    {
                        var fretStrings: com.omnifret.gplayer.collections.DoubleList = fretToStrings.get(fret)!!
                        if (fretStrings.length > 1 && chord.barreFrets.indexOf(fret) >= 0)
                        {
                            var finger: com.omnifret.gplayer.model.Fingers? = if(fingers.length > 0)  fingers.pop() else com.omnifret.gplayer.model.Fingers.IndexFinger
                            for (fretString in fretStrings)
                            {
                                var position: com.omnifret.gplayer.xml.XmlNode = fingering.addElement("Position")
                                when (finger)
                                {
                                    com.omnifret.gplayer.model.Fingers.LittleFinger -> 
                                    {
                                        position.attributes.set("finger", "Pinky")
                                    }
                                    com.omnifret.gplayer.model.Fingers.AnnularFinger -> 
                                    {
                                        position.attributes.set("finger", "Ring")
                                    }
                                    com.omnifret.gplayer.model.Fingers.MiddleFinger -> 
                                    {
                                        position.attributes.set("finger", "Middle")
                                    }
                                    com.omnifret.gplayer.model.Fingers.IndexFinger -> 
                                    {
                                        position.attributes.set("finger", "Index")
                                    }
                                    else -> { }
                                }
                                position.attributes.set("fret", (fret - chord.firstFret + 1.0).toInvariantString())
                                position.attributes.set("string", fretString.toInvariantString())
                            }
                        }
                    }
                }
                var showName: com.omnifret.gplayer.xml.XmlNode = diagram.addElement("Property")
                showName.attributes.set("name", "ShowName")
                showName.attributes.set("type", "bool")
                showName.attributes.set("value", if(chord.showName)  "true" else "false")
                var showDiagram: com.omnifret.gplayer.xml.XmlNode = diagram.addElement("Property")
                showDiagram.attributes.set("name", "ShowDiagram")
                showDiagram.attributes.set("type", "bool")
                showDiagram.attributes.set("value", if(chord.showDiagram)  "true" else "false")
                var showFingering: com.omnifret.gplayer.xml.XmlNode = diagram.addElement("Property")
                showFingering.attributes.set("name", "ShowFingering")
                showFingering.attributes.set("type", "bool")
                showFingering.attributes.set("value", if(chord.showFingering)  "true" else "false")
                var chordNode: com.omnifret.gplayer.xml.XmlNode = diagram.addElement("Chord")
                var keyNoteNode: com.omnifret.gplayer.xml.XmlNode = chordNode.addElement("KeyNote")
                keyNoteNode.attributes.set("step", "C")
                keyNoteNode.attributes.set("accidental", "Natural")
                var bassNoteNode: com.omnifret.gplayer.xml.XmlNode = chordNode.addElement("BassNote")
                bassNoteNode.attributes.set("step", "C")
                bassNoteNode.attributes.set("accidental", "Natural")
                var degree1Node: com.omnifret.gplayer.xml.XmlNode = chordNode.addElement("Degree")
                degree1Node.attributes.set("interval", "Third")
                degree1Node.attributes.set("alteration", "Major")
                degree1Node.attributes.set("omitted", "false")
                var degree2Node: com.omnifret.gplayer.xml.XmlNode = chordNode.addElement("Degree")
                degree2Node.attributes.set("interval", "Fifth")
                degree2Node.attributes.set("alteration", "Perfect")
                degree2Node.attributes.set("omitted", "false")
            }
        }
    }
    
    /**
     */
    private fun _writeSimplePropertyNode(parent: com.omnifret.gplayer.xml.XmlNode, propertyName: String, propertyValueTagName: String, propertyValue: String?): com.omnifret.gplayer.xml.XmlNode{
        var prop: com.omnifret.gplayer.xml.XmlNode = parent.addElement("Property")
        prop.attributes.set("name", propertyName)
        var propertyValueTag: com.omnifret.gplayer.xml.XmlNode = prop.addElement(propertyValueTagName)
        if (propertyValue != null)
        {
            propertyValueTag.innerText = propertyValue!!
        }
        return prop
    }
    
    /**
     */
    private fun _writeSimpleXPropertyNode(parent: com.omnifret.gplayer.xml.XmlNode, propertyId: String, propertyValueTagName: String, propertyValue: String?): com.omnifret.gplayer.xml.XmlNode{
        var prop: com.omnifret.gplayer.xml.XmlNode = parent.addElement("XProperty")
        prop.attributes.set("id", propertyId)
        var propertyValueTag: com.omnifret.gplayer.xml.XmlNode = prop.addElement(propertyValueTagName)
        if (propertyValue != null)
        {
            propertyValueTag.innerText = propertyValue!!
        }
        return prop
    }
    
    /**
     */
    private fun _writeLyricsNode(trackNode: com.omnifret.gplayer.xml.XmlNode, track: com.omnifret.gplayer.model.Track): Unit{
        var lyrics: com.omnifret.gplayer.xml.XmlNode = trackNode.addElement("Lyrics")
        lyrics.attributes.set("dispatched", "true")
        var lines: com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.Lyrics> = com.omnifret.gplayer.collections.List<com.omnifret.gplayer.model.Lyrics>(
        )
        
        for (bar in track.staves[(0).toInt()].bars)
        {
            for (voice in bar.voices)
            {
                if (!voice.isEmpty)
                {
                    for (beat in voice.beats)
                    {
                        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(beat.lyrics)))
                        {
                            if (true) {
                                var l: Double = 0.0
                                
                                while(l < beat.lyrics!!.length){
                                    while (l >= lines.length)
                                    {
                                        var newLyrics: com.omnifret.gplayer.model.Lyrics = com.omnifret.gplayer.model.Lyrics()
                                        newLyrics.startBar = bar.index
                                        newLyrics.text = "[Empty]"
                                        lines.push(newLyrics)
                                    }
                                    var line: com.omnifret.gplayer.model.Lyrics = lines[(l).toInt()]
                                    line.text = if(line.text == "[Empty]")  beat.lyrics!![(l).toInt()] else """${(line.text).toTemplate()} ${(beat.lyrics!![(l).toInt()].splitBy(" ").join("+")).toTemplate()}"""
                                    l++
                                }
                            }
                        }
                    }
                }
            }
        }
        if (true) {
            var i: Double = 0.0
            
            while(i < lines.length){
                var line: com.omnifret.gplayer.xml.XmlNode = lyrics.addElement("Line")
                line.addElement("Text").setCData(lines[(i).toInt()].text)
                line.addElement("Offset").innerText = lines[(i).toInt()].startBar.toInvariantString()
                i++
            }
        }
    }
    
    /**
     */
    private fun _writeTransposeNode(trackNode: com.omnifret.gplayer.xml.XmlNode, track: com.omnifret.gplayer.model.Track): Unit{
        var transpose: com.omnifret.gplayer.xml.XmlNode = trackNode.addElement("Transpose")
        var octaveTranspose: Double = com.omnifret.gplayer.core.ecmaScript.Math.floor(track.staves[(0).toInt()].displayTranspositionPitch / (12.0).toDouble())
        var chromaticTranspose: Double = track.staves[(0).toInt()].displayTranspositionPitch - octaveTranspose * (12.0).toDouble()
        transpose.addElement("Chromatic").innerText = chromaticTranspose.toInvariantString()
        transpose.addElement("Octave").innerText = octaveTranspose.toInvariantString()
    }
    
    /**
     */
    private fun _writeInstrumentSetNode(trackNode: com.omnifret.gplayer.xml.XmlNode, track: com.omnifret.gplayer.model.Track): Unit{
        var instrumentSet: com.omnifret.gplayer.exporter.GpifInstrumentSet = com.omnifret.gplayer.exporter.GpifSoundMapper.buildInstrumentSet(track)
        var instrumentSetNode: com.omnifret.gplayer.xml.XmlNode = trackNode.addElement("InstrumentSet")
        instrumentSetNode.addElement("Name").innerText = instrumentSet.name
        instrumentSetNode.addElement("Type").innerText = instrumentSet.type
        instrumentSetNode.addElement("LineCount").innerText = instrumentSet.lineCount.toInvariantString()
        var elementsNode: com.omnifret.gplayer.xml.XmlNode = instrumentSetNode.addElement("Elements")
        for (element in instrumentSet.elements)
        {
            var elementNode: com.omnifret.gplayer.xml.XmlNode = elementsNode.addElement("Element")
            elementNode.addElement("Name").innerText = element.name
            elementNode.addElement("Type").innerText = element.type
            elementNode.addElement("SoundbankName").innerText = element.soundbankName
            var articulationsNode: com.omnifret.gplayer.xml.XmlNode = elementNode.addElement("Articulations")
            for (articulation in element.articulations)
            {
                var articulationNode: com.omnifret.gplayer.xml.XmlNode = articulationsNode.addElement("Articulation")
                articulationNode.addElement("Name").innerText = articulation.name
                articulationNode.addElement("StaffLine").innerText = articulation.staffLine.toInvariantString()
                articulationNode.addElement("Noteheads").innerText = com.omnifret.gplayer.collections.List<String>(
                    this._mapMusicSymbol(articulation.noteHeads[(0).toInt()]), this._mapMusicSymbol(articulation.noteHeads[(1).toInt()]), this._mapMusicSymbol(articulation.noteHeads[(2).toInt()]))
                .join(" ")
                when (articulation.techniqueSymbolPlacement)
                {
                    com.omnifret.gplayer.model.TechniqueSymbolPlacement.Below -> 
