                    }
                    com.omnifret.gplayer.model.TechniqueSymbolPlacement.Above -> 
                    {
                        articulationNode.addElement("TechniquePlacement").innerText = "above"
                    }
                    else -> { }
                }
                articulationNode.addElement("TechniqueSymbol").innerText = this._mapMusicSymbol(articulation.techniqueSymbol)
                articulationNode.addElement("InputMidiNumbers").innerText = articulation.inputMidiNumbers.map(fun(n: Double): String{
                    return n.toInvariantString()
