    /**
     */
    private fun _mapMusicSymbol(symbol: com.omnifret.gplayer.model.MusicFontSymbol): String{
        if (symbol == com.omnifret.gplayer.model.MusicFontSymbol.None)
        {
            return ""
        }
        var s: String = symbol.toString()
        return s.substring(0.0, 1.0).lowercase() + s.substring(1.0)
    }
    
    /**
     */
    private fun _writeMasterBarsNode(parent: com.omnifret.gplayer.xml.XmlNode, score: com.omnifret.gplayer.model.Score): Unit{
        var masterBars: com.omnifret.gplayer.xml.XmlNode = parent.addElement("MasterBars")
        for (masterBar in score.masterBars)
        {
            this._writeMasterBarNode(masterBars, masterBar)
        }
    }
    
    /**
     */
    private fun _writeMasterBarNode(parent: com.omnifret.gplayer.xml.XmlNode, masterBar: com.omnifret.gplayer.model.MasterBar): Unit{
        var masterBarNode: com.omnifret.gplayer.xml.XmlNode = parent.addElement("MasterBar")
        var key: com.omnifret.gplayer.xml.XmlNode = masterBarNode.addElement("Key")
        var keySignature: com.omnifret.gplayer.model.KeySignature = masterBar.score.tracks[(0).toInt()].staves[(0).toInt()].bars[(masterBar.index).toInt()].keySignature
        var keySignatureType: com.omnifret.gplayer.model.KeySignatureType = masterBar.score.tracks[(0).toInt()].staves[(0).toInt()].bars[(masterBar.index).toInt()].keySignatureType
        var transposeIndex: Double = com.omnifret.gplayer.model.ModelUtils.flooredDivision(masterBar.score.tracks[(0).toInt()].staves[(0).toInt()].displayTranspositionPitch, 12.0)
        keySignature = com.omnifret.gplayer.model.ModelUtils.transposeKey(keySignature, -transposeIndex)
        key.addElement("AccidentalCount").innerText = (keySignature.toDouble()).toInvariantString()
        key.addElement("Mode").innerText = keySignatureType.toString()
        key.addElement("Sharps").innerText = "Sharps"
        masterBarNode.addElement("Time").innerText = """${(masterBar.timeSignatureNumerator).toTemplate()}/${(masterBar.timeSignatureDenominator).toTemplate()}"""
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(masterBar.actualBeamingRules)))
        {
            this._writeBarXProperties(masterBarNode, masterBar)
        }
        if (masterBar.isFreeTime)
        {
            masterBarNode.addElement("FreeTime")
        }
        var bars: com.omnifret.gplayer.collections.List<String> = com.omnifret.gplayer.collections.List<String>(
        )
        
        for (tracks in masterBar.score.tracks)
        {
            for (staves in tracks.staves)
            {
                bars.push(staves.bars[(masterBar.index).toInt()].id.toInvariantString())
            }
        }
        masterBarNode.addElement("Bars").innerText = bars.join(" ")
        if (masterBar.isDoubleBar)
        {
            masterBarNode.addElement("DoubleBar")
        }
        if (masterBar.isSectionStart)
        {
            var section: com.omnifret.gplayer.xml.XmlNode = masterBarNode.addElement("Section")
            section.addElement("Letter").setCData(masterBar.section!!.marker)
            section.addElement("Text").setCData(masterBar.section!!.text)
        }
        if (masterBar.isRepeatStart || masterBar.isRepeatEnd)
        {
            var repeat: com.omnifret.gplayer.xml.XmlNode = masterBarNode.addElement("Repeat")
            repeat.attributes.set("start", if(masterBar.isRepeatStart)  "true" else "false")
            repeat.attributes.set("end", if(masterBar.isRepeatEnd)  "true" else "false")
            if (masterBar.isRepeatEnd)
            {
                repeat.attributes.set("count", masterBar.repeatCount.toInvariantString())
            }
        }
        if (masterBar.alternateEndings > 0)
        {
            var remainingBits: Double = masterBar.alternateEndings
            var alternateEndings: com.omnifret.gplayer.collections.DoubleList = com.omnifret.gplayer.collections.DoubleList(
            )
            
            var bit: Double = 0.0
            while (remainingBits > 0)
            {
                if ((((remainingBits).toInt() shr (bit).toInt()) and 1) == 1)
                {
                    alternateEndings.push(bit + 1.0)
                    remainingBits = ((remainingBits.toInt()) and (((((1 shl (bit).toInt()).toDouble())).toInt()).toInt().inv())).toDouble()
                }
                bit++
            }
            masterBarNode.addElement("AlternateEndings").innerText = alternateEndings.join(" ")
        }
        if (masterBar.tripletFeel != com.omnifret.gplayer.model.TripletFeel.NoTripletFeel)
        {
            masterBarNode.addElement("TripletFeel").innerText = masterBar.tripletFeel.toString()
        }
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(masterBar.directions)) && masterBar.directions!!.size > 0))
        {
            var directions: com.omnifret.gplayer.xml.XmlNode = masterBarNode.addElement("Directions")
            for (d in masterBar.directions!!)
            {
                when (d)
                {
                    com.omnifret.gplayer.model.Direction.TargetFine -> 
                    {
                        directions.addElement("Target").innerText = "Fine"
                    }
                    com.omnifret.gplayer.model.Direction.TargetSegno -> 
                    {
                        directions.addElement("Target").innerText = "Segno"
                    }
                    com.omnifret.gplayer.model.Direction.TargetSegnoSegno -> 
                    {
                        directions.addElement("Target").innerText = "SegnoSegno"
                    }
                    com.omnifret.gplayer.model.Direction.TargetCoda -> 
                    {
                        directions.addElement("Target").innerText = "Coda"
                    }
                    com.omnifret.gplayer.model.Direction.TargetDoubleCoda -> 
                    {
                        directions.addElement("Target").innerText = "DoubleCoda"
                    }
                    com.omnifret.gplayer.model.Direction.JumpDaCapo -> 
                    {
                        directions.addElement("Jump").innerText = "DaCapo"
                    }
                    com.omnifret.gplayer.model.Direction.JumpDaCapoAlCoda -> 
                    {
                        directions.addElement("Jump").innerText = "DaCapoAlCoda"
                    }
                    com.omnifret.gplayer.model.Direction.JumpDaCapoAlDoubleCoda -> 
                    {
                        directions.addElement("Jump").innerText = "DaCapoAlDoubleCoda"
                    }
                    com.omnifret.gplayer.model.Direction.JumpDaCapoAlFine -> 
                    {
                        directions.addElement("Jump").innerText = "DaCapoAlFine"
                    }
                    com.omnifret.gplayer.model.Direction.JumpDalSegno -> 
                    {
                        directions.addElement("Jump").innerText = "DaSegno"
                    }
                    com.omnifret.gplayer.model.Direction.JumpDalSegnoAlCoda -> 
                    {
                        directions.addElement("Jump").innerText = "DaSegnoAlCoda"
                    }
                    com.omnifret.gplayer.model.Direction.JumpDalSegnoAlDoubleCoda -> 
                    {
                        directions.addElement("Jump").innerText = "DaSegnoAlDoubleCoda"
                    }
                    com.omnifret.gplayer.model.Direction.JumpDalSegnoAlFine -> 
                    {
                        directions.addElement("Jump").innerText = "DaSegnoAlFine"
                    }
                    com.omnifret.gplayer.model.Direction.JumpDalSegnoSegno -> 
                    {
                        directions.addElement("Jump").innerText = "DaSegnoSegno"
                    }
                    com.omnifret.gplayer.model.Direction.JumpDalSegnoSegnoAlCoda -> 
                    {
                        directions.addElement("Jump").innerText = "DaSegnoSegnoAlCoda"
                    }
                    com.omnifret.gplayer.model.Direction.JumpDalSegnoSegnoAlDoubleCoda -> 
                    {
                        directions.addElement("Jump").innerText = "DaSegnoSegnoAlDoubleCoda"
                    }
                    com.omnifret.gplayer.model.Direction.JumpDalSegnoSegnoAlFine -> 
                    {
                        directions.addElement("Jump").innerText = "DaSegnoSegnoAlFine"
                    }
                    com.omnifret.gplayer.model.Direction.JumpDaCoda -> 
                    {
                        directions.addElement("Jump").innerText = "DaCoda"
                    }
                    com.omnifret.gplayer.model.Direction.JumpDaDoubleCoda -> 
                    {
                        directions.addElement("Jump").innerText = "DaDoubleCoda"
                    }
                    else -> { }
                }
            }
        }
        this._writeFermatas(masterBarNode, masterBar)
    }
    
    /**
     */
    private fun _writeBarXProperties(masterBarNode: com.omnifret.gplayer.xml.XmlNode, masterBar: com.omnifret.gplayer.model.MasterBar): Unit{
        var properties: com.omnifret.gplayer.xml.XmlNode = masterBarNode.addElement("XProperties")
        var beamingRules: com.omnifret.gplayer.model.BeamingRules? = masterBar.actualBeamingRules
        if (com.omnifret.gplayer.core.TypeHelper.isTruthy(com.omnifret.gplayer.core.TypeHelper.isTruthy(beamingRules)))
        {
            var rule: com.omnifret.gplayer.core.IArrayTuple<com.omnifret.gplayer.model.Duration, com.omnifret.gplayer.collections.DoubleList> = beamingRules!!.findRule(com.omnifret.gplayer.model.Duration.Eighth)
            var durationProp: Double = rule.v0.toDouble()
            var groupSizeFactor: Double = 1.0
            if (rule.v0 == com.omnifret.gplayer.model.Duration.Quarter)
            {
                durationProp = 8.0
                groupSizeFactor = 2.0
            }
            this._writeSimpleXPropertyNode(properties, "1124139010", "Int", durationProp.toInvariantString())
            var startGroupid: Double = 1124139264.0
            var i: Double = 0.0
            while (startGroupid < 1124139295 && i < rule.v1.length)
            {
                this._writeSimpleXPropertyNode(properties, (startGroupid + i).toInvariantString(), "Int", (rule.v1[(i).toInt()] * groupSizeFactor).toInvariantString())
                i++
            }
        }
    }
    
    /**
     */
    private fun _writeFermatas(parent: com.omnifret.gplayer.xml.XmlNode, masterBar: com.omnifret.gplayer.model.MasterBar): Unit{
        var fermataCount: Double = masterBar.fermata?.size ?: 0.0
        if (fermataCount == 0.0)
        {
            return
        }
        if (fermataCount > 0)
        {
            var fermatas: com.omnifret.gplayer.xml.XmlNode = parent.addElement("Fermatas")
            for ((offset, fermata) in masterBar.fermata!!)
            {
                this._writeFermata(fermatas, offset, fermata)
            }
        }
    }
    
    /**
     */
    private fun _writeFermata(parent: com.omnifret.gplayer.xml.XmlNode, offset: Double, fermata: com.omnifret.gplayer.model.Fermata): Unit{
        var numerator: Double = -1.0
        var denominator: Double = 1.0
        if (offset > 0)
        {
            while (denominator < 10)
            {
                numerator = (offset / com.omnifret.gplayer.midi.MidiUtils.QuarterTime) * denominator
                if (numerator == com.omnifret.gplayer.core.ecmaScript.Math.floor(numerator))
                {
                    break
                }
                numerator = -1.0
                denominator++
            }
        }
        else 
        {
            numerator = 0.0
            denominator = 1.0
        }
        if (numerator == -1.0)
        {
            return
        }
        var fermataNode: com.omnifret.gplayer.xml.XmlNode = parent.addElement("Fermata")
        fermataNode.addElement("Type").innerText = fermata.type.toString()
        fermataNode.addElement("Length").innerText = fermata.length.toInvariantString()
        fermataNode.addElement("Offset").innerText = """${(numerator).toTemplate()}/${(denominator).toTemplate()}"""
    }
    
    /**
     */
    private fun _writeBarNode(parent: com.omnifret.gplayer.xml.XmlNode, bar: com.omnifret.gplayer.model.Bar): Unit{
        var barNode: com.omnifret.gplayer.xml.XmlNode = parent.addElement("Bar")
        barNode.attributes.set("id", bar.id.toInvariantString())
        barNode.addElement("Voices").innerText = bar.voices.map(fun(v: com.omnifret.gplayer.model.Voice): String{
            return (if(v.isEmpty)  "-1" else v.id.toInvariantString())
        }
        ).join(" ")
        barNode.addElement("Clef").innerText = bar.clef.toString()
        if (bar.clefOttava != com.omnifret.gplayer.model.Ottavia.Regular)
        {
            barNode.addElement("Ottavia").innerText = bar.clefOttava.toString().substr(1.0)
        }
        if (bar.simileMark != com.omnifret.gplayer.model.SimileMark.None)
        {
            barNode.addElement("SimileMark").innerText = bar.simileMark.toString()
        }
    }
    
    /**
     */
    private fun _writeVoiceNode(parent: com.omnifret.gplayer.xml.XmlNode, voice: com.omnifret.gplayer.model.Voice): Unit{
        if (voice.isEmpty)
        {
            return
        }
        var voiceNode: com.omnifret.gplayer.xml.XmlNode = parent.addElement("Voice")
        voiceNode.attributes.set("id", voice.id.toInvariantString())
        voiceNode.addElement("Beats").innerText = voice.beats.map(fun(v: com.omnifret.gplayer.model.Beat): Double{
            return v.id
        }
        ).join(" ")
    }
    
